.canvas-node-container .markdown-rendere.background-image:
linear-gradient(
      0deg,
      transparent 0px,
      var(--color-accent-trans) 1px,
      var(--color-accent-trans) 2px,
      transparent 3px
    ),
    linear-gradient(
      90deg,
      transparent calc(var(--grid-size) - 3px),
      var(--color-accent-trans) calc(var(--grid-size) - 2px),
      var(--color-accent-trans) calc(var(--grid-size) - 1px),
      transparent var(--grid-size)
    )
